import type { ComponentPropsWithRef, CSSProperties, ReactNode } from "react";
import { cn } from "@/lib/utils";
import { composeRefs } from "@/lib/compose-refs";
import { useOverflow } from "@/hooks/use-overflow";
import { TooltipRoot as Tooltip } from "../tooltip/tooltip";
import { TooltipContent } from "../tooltip/tooltip-content";
import {
  PopoverTrigger as TooltipTrigger,
  type PopoverTriggerRenderProps,
} from "../popover/popover-trigger";

function resolveTooltipContent(
  tooltip: ReactNode | boolean | undefined,
  children: string,
): ReactNode | null {
  if (tooltip === false) return null;
  if (tooltip != null && tooltip !== true) return tooltip;
  return children;
}

export interface OverflowTextProps
  extends Omit<ComponentPropsWithRef<"div">, "children"> {
  children: string;
  lines?: number;
  tooltip?: ReactNode | boolean;
}

function clampStyle(lines: number): CSSProperties | undefined {
  if (lines <= 1) return undefined;
  return {
    display: "-webkit-box",
    WebkitLineClamp: lines,
    WebkitBoxOrient: "vertical",
    overflow: "hidden",
  };
}

export function OverflowText({
  children,
  lines = 1,
  tooltip,
  className,
  ref: forwardedRef,
  ...props
}: OverflowTextProps) {
  const { ref, isOverflowing } = useOverflow<HTMLDivElement>(lines > 1 ? "vertical" : "horizontal");

  const resolvedTooltip = resolveTooltipContent(tooltip, children);
  const style = clampStyle(lines);
  const content = (
    <div
      ref={composeRefs(ref, forwardedRef)}
      className={cn(lines === 1 && "truncate", className)}
      style={style}
      {...props}
    >
      {children}
    </div>
  );

  if (resolvedTooltip != null && !isOverflowing) {
    return content;
  }

  if (resolvedTooltip != null) {
    return (
      <Tooltip enabled={isOverflowing}>
        <TooltipTrigger>
          {({ ref: triggerRef, className: triggerCn, role, ...restTrigger }: PopoverTriggerRenderProps) => (
            <div
              ref={composeRefs(ref, forwardedRef, triggerRef)}
              role={role}
              className={cn(lines === 1 && "truncate", className, triggerCn)}
              style={style}
              {...props}
              {...restTrigger}
            >
              {children}
            </div>
          )}
        </TooltipTrigger>
        <TooltipContent>{resolvedTooltip}</TooltipContent>
      </Tooltip>
    );
  }

  return content;
}

"use client";

import { Children, type ComponentPropsWithRef, type ReactNode } from "react";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import { useOverflowItems } from "@/hooks/use-overflow-items";

export interface OverflowIndicatorRenderProps {
  count: number;
}

export type OverflowIndicatorRender =
  | ((props: OverflowIndicatorRenderProps) => ReactNode)
  | ReactNode;

const hiddenClass = "invisible absolute pointer-events-none";

export interface OverflowItemsProps
  extends Omit<ComponentPropsWithRef<"div">, "children"> {
  children: ReactNode;
  indicator?: OverflowIndicatorRender;
  gap?: string;
}

function DefaultBadge() {
  return (
    <span aria-hidden="true" className="inline-flex items-center border border-dashed border-foreground/30 px-1.5 py-0.5 font-mono text-[10px] text-muted-foreground">
      …
    </span>
  );
}

function IndicatorDisplay({ indicator, count }: { indicator?: OverflowIndicatorRender; count: number }) {
  if (typeof indicator === "function") {
    return <>{indicator({ count })}</>;
  }
  return <>{indicator ?? <DefaultBadge />}</>;
}

export function OverflowItems({
  children,
  indicator,
  gap = "gap-1",
  className,
  ref,
  ...props
}: OverflowItemsProps) {
  const itemCount = Children.count(children);
  const { ref: overflowRef, visibleCount, overflowCount } =
    useOverflowItems({ itemCount });

  return (
    <div
      ref={composeRefs(overflowRef, ref)}
      className={cn("relative flex items-center overflow-clip", gap, className)}
      {...props}
    >
      {Children.map(children, (item, i) => (
        <div className={cn("shrink-0", i >= visibleCount && hiddenClass)} inert={i >= visibleCount || undefined}>
          {item}
        </div>
      ))}
      <div
        className={cn("shrink-0", overflowCount === 0 && hiddenClass)}
        role={overflowCount > 0 ? "status" : undefined}
        aria-label={overflowCount > 0 ? `${overflowCount} more items` : undefined}
        inert={overflowCount === 0 || undefined}
      >
        <IndicatorDisplay indicator={indicator} count={overflowCount} />
      </div>
    </div>
  );
}

