function hasMatch(labels: ReadonlyMap<string, SelectOptionMetadata>, query: string): boolean {
  for (const option of labels.values()) {
    if (matchesSearch(option.label, query)) return true;
  }
  return false;
}

"use client";

import { useState, useRef, useId, useCallback, useMemo, type AriaAttributes, type RefObject } from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { useFormReset } from "@/hooks/use-form-reset";
import { useOutsideClick } from "@/hooks/use-outside-click";
import type { SelectContextValue, SelectOptionMetadata } from "./select-context";
import { matchesSearch } from "@/lib/search";

type SelectValue = string | null | string[];

interface UseSelectStateBaseOptions {
  open?: boolean;
  openControlled?: boolean;
  onOpenChange?: (open: boolean) => void;
  defaultOpen?: boolean;
  highlighted?: string | null;
  highlightedControlled?: boolean;
  onHighlightChange?: (value: string | null) => void;
  /** @deprecated Use `onHighlightChange` for controlled highlight updates. */
  onHighlight?: (value: string | null) => void;
  disabled?: boolean;
  variant?: "default" | "card";
  ariaInvalid?: AriaAttributes["aria-invalid"];
  required?: boolean;
  options: ReadonlyMap<string, SelectOptionMetadata>;
}

interface UseSelectStateSingleOptions extends UseSelectStateBaseOptions {
  multiple?: false;
  value?: string;
  valueControlled?: boolean;
  onValueChange?: (value: string) => void;
  /** @deprecated Use `onValueChange` for controlled value updates. */
  onChange?: (value: string) => void;
  defaultValue?: string;
}

interface UseSelectStateMultipleOptions extends UseSelectStateBaseOptions {
  multiple: true;
  value?: string[];
  valueControlled?: boolean;
  onValueChange?: (value: string[]) => void;
  /** @deprecated Use `onValueChange` for controlled value updates. */
  onChange?: (value: string[]) => void;
  defaultValue?: string[];
}

export type UseSelectStateOptions =
  | UseSelectStateSingleOptions
  | UseSelectStateMultipleOptions;

export interface UseSelectStateReturn {
  contextValue: SelectContextValue;
  wrapperRef: RefObject<HTMLDivElement | null>;
}

function getDefaultSelectValue(multiple: boolean, defaultValue: SelectValue | undefined): SelectValue {
  return defaultValue ?? (multiple ? [] : null);
}

function getSelectValueChangeHandler(options: UseSelectStateOptions) {
  if (options.multiple) {
    const onValueChange = options.onValueChange ?? options.onChange;
    return onValueChange
      ? (nextValue: SelectValue) => {
          if (Array.isArray(nextValue)) onValueChange(nextValue);
        }
      : undefined;
  }

  const onValueChange = options.onValueChange ?? options.onChange;
  return onValueChange
    ? (nextValue: SelectValue) => {
        if (typeof nextValue === "string") onValueChange(nextValue);
      }
    : undefined;
}

export function useSelectState(options: UseSelectStateOptions): UseSelectStateReturn {
  const {
    open: controlledOpen,
    openControlled,
    onOpenChange,
    defaultOpen = false,
    value: controlledValue,
    valueControlled,
    defaultValue,
    highlighted: controlledHighlighted,
    highlightedControlled,
    onHighlight,
    onHighlightChange,
    multiple = false,
    disabled = false,
    variant = "default",
    ariaInvalid,
    required,
    options: optionMetadata,
  } = options;
  const resetValue = useMemo(
    () => getDefaultSelectValue(multiple, defaultValue),
    [defaultValue, multiple],
  );
  const valueChangeHandler = useMemo(
    () => getSelectValueChangeHandler(options),
    [multiple, options.onChange, options.onValueChange],
  );
  const isOpenControlled = openControlled ?? controlledOpen !== undefined;
  const isValueControlled = valueControlled ?? controlledValue !== undefined;
  const isHighlightedControlled = highlightedControlled ?? controlledHighlighted !== undefined;

  const [isOpen, setIsOpen] = useControllableState<boolean>({
    value: isOpenControlled ? controlledOpen ?? false : controlledOpen,
    controlled: isOpenControlled,
    defaultValue: defaultOpen,
    onChange: onOpenChange,
  });
  const [value, setValue] = useControllableState<SelectValue>({
    value: isValueControlled ? controlledValue ?? resetValue : controlledValue,
    controlled: isValueControlled,
    defaultValue: resetValue,
    onChange: valueChangeHandler,
  });
  const [searchQuery, setSearchQuery] = useState("");
  const [nativeInvalid, setNativeInvalid] = useState(false);
  const [highlighted, setHighlighted] = useControllableState<string | null>({
    value: isHighlightedControlled ? controlledHighlighted ?? null : controlledHighlighted,
    controlled: isHighlightedControlled,
    defaultValue: null,
    onChange: onHighlightChange ?? onHighlight,
  });

  const triggerRef = useRef<HTMLButtonElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const searchInputRef = useRef<HTMLInputElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);
  const listboxId = useId();

  const handleOpenChange = useCallback((open: boolean) => {
    if (disabled) return;
    setIsOpen(open);
    if (!open) {
      setSearchQuery("");
      setHighlighted(null);
    }
  }, [disabled, setIsOpen, setHighlighted]);

  const outsideClickExcludeRefs = useMemo(() => [contentRef], [contentRef]);
  useOutsideClick(wrapperRef, () => handleOpenChange(false), isOpen, outsideClickExcludeRefs);

  const onSearchChange = useCallback((query: string) => {
    setSearchQuery(query);
    if (highlighted !== null) {
      const option = optionMetadata.get(highlighted);
      if (option && (!matchesSearch(option.label, query) || option.disabled)) {
        setHighlighted(null);
      }
    }
  }, [highlighted, optionMetadata, setHighlighted]);

  const selectItem = useCallback((itemValue: string) => {
    const option = optionMetadata.get(itemValue);
    if (disabled || !option || option.disabled || !matchesSearch(option.label, searchQuery)) return;
    setNativeInvalid(false);
    if (multiple) {
      setValue((prev) => {
        const current = Array.isArray(prev) ? prev : [];
        return current.includes(itemValue)
          ? current.filter((v) => v !== itemValue)
          : [...current, itemValue];
      });
    } else {
      setValue(itemValue);
      handleOpenChange(false);
      triggerRef.current?.focus();
    }
  }, [disabled, multiple, optionMetadata, searchQuery, setValue, handleOpenChange]);

  useFormReset(wrapperRef, resetValue, setValue, !isValueControlled);

  const hasRequiredValue = Array.isArray(value) ? value.length > 0 : value !== null && value !== "";
  const resolvedAriaInvalid = nativeInvalid && required && !hasRequiredValue ? true : ariaInvalid;

  const onNativeInvalid = useCallback(() => {
    setNativeInvalid(true);
    (searchInputRef.current ?? triggerRef.current)?.focus();
  }, []);

  const contextValue: SelectContextValue = useMemo(() => ({
    open: isOpen,
    disabled,
    onOpenChange: handleOpenChange,
    value,
    multiple,
    searchQuery,
    onSearchChange,
    highlighted,
    onHighlight: setHighlighted,
    selectItem,
    options: optionMetadata,
    triggerRef,
    contentRef,
    searchInputRef,
    variant,
    listboxId,
    triggerId: `${listboxId}-trigger`,
    ariaInvalid: resolvedAriaInvalid,
    required: required || undefined,
    onNativeInvalid,
  }), [isOpen, disabled, handleOpenChange, value, multiple, searchQuery, onSearchChange, highlighted, setHighlighted, selectItem, optionMetadata, variant, listboxId, resolvedAriaInvalid, required, onNativeInvalid]);

  return { contextValue, wrapperRef };
}

"use client";

import type { ReactNode, HTMLAttributes, Ref } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { useSpinnerAnimation } from "./use-spinner-animation";
import { SnakeGrid, SNAKE_FRAME_COUNT } from "./spinner-snake-grid";

export type SpinnerSize = "sm" | "md" | "lg";
export type SpinnerVariant = "snake" | "braille" | "dots" | "pulse";
export type SpinnerLabelPosition = "right" | "left" | "top" | "bottom";
export type SpinnerGap = "none" | "sm" | "md" | "lg";

const BRAILLE_FRAMES = ["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"] as const;
const DOTS_FRAMES = [".  ", ".. ", "..."] as const;
const PULSE_FRAMES = ["░", "▒", "▓", "█", "▓", "▒", "░"] as const;

// Fixed width prevents layout shift during dot animation ("." → ".." → "...")
const DOTS_FIXED_WIDTH = "w-7";

const VARIANT_CONFIG: Record<SpinnerVariant, { frames: number; speed: number }> = {
  snake: { frames: SNAKE_FRAME_COUNT, speed: 100 },
  braille: { frames: BRAILLE_FRAMES.length, speed: 80 },
  dots: { frames: DOTS_FRAMES.length, speed: 300 },
  pulse: { frames: PULSE_FRAMES.length, speed: 80 },
};

const spinnerVariants = cva("inline-flex items-center font-mono", {
  variants: {
    size: {
      sm: "text-xs",
      md: "text-sm",
      lg: "text-base",
    },
    labelPosition: {
      right: "flex-row",
      left: "flex-row-reverse",
      bottom: "flex-col",
      top: "flex-col-reverse",
    },
    gap: {
      none: "gap-0",
      sm: "gap-1",
      md: "gap-2",
      lg: "gap-3",
    },
  },
  defaultVariants: { size: "md", labelPosition: "right", gap: "md" },
});

export interface SpinnerProps
  extends HTMLAttributes<HTMLSpanElement>,
    VariantProps<typeof spinnerVariants> {
  variant?: SpinnerVariant;
  size?: SpinnerSize;
  labelPosition?: SpinnerLabelPosition;
  gap?: SpinnerGap;
  speed?: number;
  children?: ReactNode;
  ref?: Ref<HTMLSpanElement>;
}

function SpinnerAnimation({ variant, frame, size }: { variant: SpinnerVariant; frame: number; size: SpinnerSize }) {
  const safeFrame = frame % VARIANT_CONFIG[variant].frames;
  if (variant === "snake") return <SnakeGrid frame={safeFrame} size={size} />;
  if (variant === "braille") return <>{BRAILLE_FRAMES[safeFrame]}</>;
  if (variant === "dots") {
    return <span className={cn("inline-block whitespace-pre", DOTS_FIXED_WIDTH)}>{DOTS_FRAMES[safeFrame]}</span>;
  }
  return <>{PULSE_FRAMES[safeFrame]}</>;
}

export function Spinner({
  variant = "snake",
  size,
  labelPosition,
  gap,
  speed: requestedSpeed,
  className,
  children,
  ref,
  ...props
}: SpinnerProps) {
  const { frames: totalFrames, speed: defaultSpeed } = VARIANT_CONFIG[variant];
  const resolvedSpeed =
    typeof requestedSpeed === "number" && Number.isFinite(requestedSpeed) && requestedSpeed > 0
      ? requestedSpeed
      : defaultSpeed;
  const frame = useSpinnerAnimation({ totalFrames, speed: resolvedSpeed });
  const resolvedSize = size ?? "md";

  return (
    <span
      ref={ref}
      role="status"
      aria-live="polite"
      aria-label={children ? undefined : "Loading"}
      className={cn(
        spinnerVariants({ size: resolvedSize, labelPosition, gap }),
        className,
      )}
      {...props}
    >
      <span aria-hidden="true" className="inline-flex items-center">
        <SpinnerAnimation variant={variant} frame={frame} size={resolvedSize} />
      </span>
      {children}
    </span>
  );
}

"use client";

import { useState, useEffect } from "react";

interface UseSpinnerAnimationOptions {
  totalFrames: number;
  speed: number;
}

export function useSpinnerAnimation({ totalFrames, speed }: UseSpinnerAnimationOptions): number {
  const [frame, setFrame] = useState(0);

  useEffect(() => {
    if (!Number.isFinite(totalFrames) || totalFrames <= 0 || !Number.isFinite(speed) || speed <= 0) {
      setFrame(0);
      return;
    }

    let intervalId: ReturnType<typeof setInterval> | undefined;
    const mql = typeof window !== "undefined" && typeof window.matchMedia === "function"
      ? window.matchMedia("(prefers-reduced-motion: reduce)")
      : null;

    function sync() {
      if (intervalId !== undefined) {
        clearInterval(intervalId);
        intervalId = undefined;
      }
      if (mql?.matches) {
        setFrame(0);
      } else {
        intervalId = setInterval(() => setFrame(f => (f + 1) % totalFrames), speed);
      }
    }

    sync();
    mql?.addEventListener("change", sync);

    return () => {
      mql?.removeEventListener("change", sync);
      if (intervalId !== undefined) clearInterval(intervalId);
    };
  }, [speed, totalFrames]);

  return frame;
}

"use client";

import { cn } from "@/lib/utils";
import type { SpinnerSize } from "./spinner";

// 3×3 grid positions (0–8, left-to-right top-to-bottom).
// Perimeter traversal order for clockwise snake movement:
//   0 1 2
//   3 · 5   ← center (4) is always invisible
//   6 7 8
const SNAKE_PERIMETER = [0, 1, 2, 5, 8, 7, 6, 3] as const;
const SNAKE_TAIL_LENGTH = 3;

export const SNAKE_FRAME_COUNT = SNAKE_PERIMETER.length;

const PERIMETER_POSITION = new Map<number, number>(SNAKE_PERIMETER.map((cell, i) => [cell, i]));
const TRAIL_OPACITIES = [1, 0.6, 0.3] as const;
const INACTIVE_OPACITY = 0.15;

const DOT_SIZES: Record<SpinnerSize, { dot: string; gap: string }> = {
  sm: { dot: "h-1 w-1", gap: "gap-[3px]" },
  md: { dot: "h-1.5 w-1.5", gap: "gap-[3px]" },
  lg: { dot: "h-2 w-2", gap: "gap-1" },
};

const CELL_INDICES = [0, 1, 2, 3, 4, 5, 6, 7, 8] as const;

function getCellOpacity(frame: number, cellIndex: number): number {
  const positionInPerimeter = PERIMETER_POSITION.get(cellIndex);
  if (positionInPerimeter === undefined) return 0;
  const distanceBehindHead = (frame - positionInPerimeter + SNAKE_PERIMETER.length) % SNAKE_PERIMETER.length;
  return distanceBehindHead < SNAKE_TAIL_LENGTH ? TRAIL_OPACITIES[distanceBehindHead] : INACTIVE_OPACITY;
}

interface SnakeGridProps {
  frame: number;
  size: SpinnerSize;
}

export function SnakeGrid({ frame, size }: SnakeGridProps) {
  const { dot, gap } = DOT_SIZES[size];
  const dotClassName = cn("rounded-sm bg-current", dot);

  return (
    <span className={cn("grid grid-cols-3", gap)}>
      {CELL_INDICES.map(cellIndex => (
        <span
          key={cellIndex}
          className={dotClassName}
          style={{ opacity: getCellOpacity(frame, cellIndex) }}
        />
      ))}
    </span>
  );
}

